INSERT INTO artist (id, artist_name, artist_avatar, artist_profile, region, create_time, update_time, is_delete) VALUES
                                                                                                                     (1, '周杰伦', 'https://example.com/avatars/jaychou.jpg', '华语流行乐天王，音乐制作人、导演、演员。2000年出道，以其独特的R&B和中国风音乐风格闻名，代表作品《七里香》《青花瓷》《稻香》等', '中国台湾', NOW(), NOW(), 0),
                                                                                                                     (2, '林俊杰', 'https://example.com/avatars/jjlin.jpg', '新加坡歌手、音乐制作人、金曲歌王。以其出色的唱功和创作能力著称，代表作品《江南》《修炼爱情》《不为谁而作的歌》', '新加坡', NOW(), NOW(), 0),
                                                                                                                     (3, '陈奕迅', 'https://example.com/avatars/easonchan.jpg', '香港歌手、演员，被誉为歌神接班人。嗓音独特，情感表达深刻，代表作品《富士山下》《K歌之王》《浮夸》', '中国香港', NOW(), NOW(), 0),
                                                                                                                     (4, '王力宏', 'https://example.com/avatars/leehomwang.jpg', '美籍华人歌手、音乐制作人、演员。擅长多种乐器，将西洋音乐与中国风完美融合，代表作品《唯一》《心中的日月》《落叶归根》', '美国', NOW(), NOW(), 0),
                                                                                                                     (5, '张杰', 'https://example.com/avatars/jasonzhang.jpg', '内地实力派男歌手，以其高亢清亮的嗓音著称。代表作品《天下》《逆战》《这，就是爱》', '中国内地', NOW(), NOW(), 0),
                                                                                                                     (6, '薛之谦', 'https://example.com/avatars/jokerxue.jpg', '创作型歌手、段子手。以深情的情歌创作著称，代表作品《演员》《丑八怪》《认真的雪》', '中国内地', NOW(), NOW(), 0),
                                                                                                                     (7, '李健', 'https://example.com/avatars/lijian.jpg', '音乐诗人，水木年华前成员。以其温润如玉的嗓音和诗意的歌词著称，代表作品《传奇》《风吹麦浪》《贝加尔湖畔》', '中国内地', NOW(), NOW(), 0),
